// src/dao/StudyMethodDAO.js
import { supabase } from '../utils/supabaseClient';

const StudyMethodDAO = {
  async findAll() {
    const { data, error } = await supabase
      .from('study_methods')
      .select('*')
      .order('created_at', { ascending: false });
    if (error) throw error;
    return data;
  },

  async findById(id) {
    const { data, error } = await supabase
      .from('study_methods')
      .select('*')
      .eq('id', id)
      .single();
    if (error) throw error;
    return data;
  },

  async create(methodData) {
    const { data, error } = await supabase
      .from('study_methods')
      .insert([methodData])
      .select()
      .single();
    if (error) throw error;
    return data;
  },

  async update(id, methodData) {
    const { data, error } = await supabase
      .from('study_methods')
      .update({ ...methodData, updated_at: new Date().toISOString() })
      .eq('id', id)
      .select()
      .single();
    if (error) throw error;
    return data;
  },

  async delete(id) {
    const { error } = await supabase
      .from('study_methods')
      .delete()
      .eq('id', id);
    if (error) throw error;
    return true;
  },

  async findByCategory(category) {
    const { data, error } = await supabase
      .from('study_methods')
      .select('*')
      .eq('category', category)
      .order('created_at', { ascending: false });
    if (error) throw error;
    return data;
  },

  async search(term) {
    const { data, error } = await supabase
      .from('study_methods')
      .select('*')
      .or(`name.ilike.%${term}%,description.ilike.%${term}%`)
      .order('created_at', { ascending: false });
    if (error) throw error;
    return data;
  }
};

export default StudyMethodDAO;
